import{_ as r,o,c as t,ag as a}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Introducing Aerosol","description":"Aerosol is an open-source, local disk cleaner for macOS, Windows, and Linux — with risk-aware cleanup, optional Trash, and a File recovery mode for read-only scans and copy-out recovery.","frontmatter":{"title":"Introducing Aerosol","description":"Aerosol is an open-source, local disk cleaner for macOS, Windows, and Linux — with risk-aware cleanup, optional Trash, and a File recovery mode for read-only scans and copy-out recovery.","date":"2026-04-01T00:00:00.000Z"},"headers":[],"relativePath":"blog/introducing-aerosol.md","filePath":"blog/introducing-aerosol.md","lastUpdated":1775592403000}'),s={name:"blog/introducing-aerosol.md"};function n(i,e,l,d,c,h){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="introducing-aerosol" tabindex="-1">Introducing Aerosol <a class="header-anchor" href="#introducing-aerosol" aria-label="Permalink to &quot;Introducing Aerosol&quot;">​</a></h1><p><strong>Aerosol</strong> is a desktop app for finding caches, logs, and developer clutter you can actually understand before you delete anything — and, in a separate <strong>File recovery</strong> mode, for <strong>read-only</strong> scans of a folder you pick, <strong>previews</strong> of images and videos, and <strong>copying</strong> matches to a safe output path. It runs on <strong>macOS</strong> (Apple Silicon and Intel), <strong>Windows</strong>, and <strong>Linux</strong>, built with <a href="https://tauri.app/" target="_blank" rel="noreferrer">Tauri</a> so the UI stays fast and your file list never needs our servers.</p><h2 id="who-it-s-for" tabindex="-1">Who it’s for <a class="header-anchor" href="#who-it-s-for" aria-label="Permalink to &quot;Who it’s for&quot;">​</a></h2><ul><li>People who outgrew “free cleaner” apps that hide what they remove</li><li>Developers with Docker layers, old <code>node_modules</code>, and tool caches</li><li>Anyone who wants <strong>dry-run preview</strong>, <strong>risk hints</strong>, and <strong>Trash</strong> (where the OS supports it) instead of irreversible one-tap wipes</li></ul><h2 id="what-makes-it-different" tabindex="-1">What makes it different <a class="header-anchor" href="#what-makes-it-different" aria-label="Permalink to &quot;What makes it different&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Idea</th><th>How Aerosol approaches it</th></tr></thead><tbody><tr><td>Transparency</td><td>Open source — scan rules and UI are on <a href="https://github.com/januscaler/aerosol" target="_blank" rel="noreferrer">GitHub</a>.</td></tr><tr><td>Control</td><td>You pick categories and paths; we don’t “optimize” your disk in secret.</td></tr><tr><td>Safety</td><td>Items are grouped so <strong>safe</strong> junk is easier to separate from things that deserve a second look.</td></tr><tr><td>File recovery</td><td>A dedicated mode walks a <strong>directory tree</strong> you choose, finds files by type signatures, and <strong>never writes</strong> to that source — only copies out to a folder you select. See the <a href="/blog/file-recovery-mode">blog post on recovery</a>.</td></tr></tbody></table><h2 id="try-it" tabindex="-1">Try it <a class="header-anchor" href="#try-it" aria-label="Permalink to &quot;Try it&quot;">​</a></h2><p>Installers are on the <a href="/#download">home page</a> and <a href="https://github.com/januscaler/aerosol/releases" target="_blank" rel="noreferrer">GitHub Releases</a>. On Apple Silicon Macs, grab the <strong>aarch64</strong> <code>.dmg</code>; unsigned builds may need a one-time <strong>Open</strong> from the right-click menu — see the <a href="/manual#macos-install-github-release-builds">manual → macOS install</a>.</p><p>We’re early; expect rough edges and <a href="https://github.com/januscaler/aerosol/issues" target="_blank" rel="noreferrer">issues</a> welcome.</p>',9)])])}const p=r(s,[["render",n]]);export{g as __pageData,p as default};
